#include <vector>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    //  Parallelise over rows of C (and A).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* __restrict a_row = A[i].data();
        double* __restrict c_row = C[i].data();

        // Scale C[i] by beta
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        // For each column k of A and row k of B
        for (int k = 0; k < nk; ++k)
        {
            double a_val  = a_row[k] * alpha;          // pre‑multiply once
            double* __restrict b_row = B[k].data();   // row k of B
            double* __restrict c_ptr = c_row;         // alias for inner loop

            // Accumulate contribution of A[i][k] * B[k][j]
            #pragma omp simd
            for (int j = 0; j < nj; ++j)
                c_ptr[j] += a_val * b_row[j];
        }
    }
}
