void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Pointers to the underlying data for fast access
    double* xb = x.data();
    const double* bb = b.data();

    // Simple bounds check (optional for safety, remove for pure speed)
    // for (int i = 0; i < n; ++i) assert(L[i].size() == static_cast<std::size_t>(n));

    for (int i = 0; i < n; ++i) {
        double sum = bb[i];
        const std::vector<double>& Li = L[i];
        // The inner loop is a classic dot‑product
        // -> allow the compiler to vectorize it
        #pragma omp simd reduction(-:sum)
        for (int j = 0; j < i; ++j) {
            sum -= Li[j] * xb[j];
        }
        xb[i] = sum / Li[i];
    }
}
