#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

static inline int min_avx2(int a, int b) noexcept {
    // Branch‑free minimum
    return a ^ ((a ^ b) & -static_cast<int>(a < b));
}

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D vector to a 1‑D array for better cache locality
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[i * n + j] = path[i][j];

    // Parallel outer loop over k, inner loops kept simple
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < n; ++k) {
        int k_off = k * n;
        for (int i = 0; i < n; ++i) {
            int i_off = i * n;
            int ik = flat[i_off + k];
            for (int j = 0; j < n; ++j) {
                int idx = i_off + j;
                int cand = ik + flat[k_off + j];
                flat[idx] = min_avx2(flat[idx], cand);
            }
        }
    }

    // Copy back to the original 2-D representation
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            path[i][j] = flat[i * n + j];
}
