#include <cmath>
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Use a contiguous view for faster indexing
    std::vector<double*> rowPtr(n);
    for (int i = 0; i < n; ++i) rowPtr[i] = A[i].data();

    for (int i = 0; i < n; ++i) {
        double* Ai = rowPtr[i];
        // Upper triangular part (i > j)
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* Aj = rowPtr[j];
            const int kk = j;
            for (int k = 0; k < kk; ++k) {
                sum += Ai[k] * Aj[k];
            }
            Ai[j] = (Ai[j] - sum) / Aj[j];
        }

        // Diagonal element
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += Ai[k] * Ai[k];
        }
        Ai[i] = std::sqrt(Ai[i] - sum);
    }
}
