#include <vector>
#include <omp.h>

void kernel_jacobi_2d(int tsteps, int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {
    const double coef = 0.2;
    /* 8‑thread OpenMP parallelization.  The two nested loops that
       perform the stencil updates are collapsed into a single
       parallel region and are static‑scheduled for even
       workload distribution.  The outer time‑step loop remains
       sequential because the two updates must be performed
       in order for each time step. */
    for (int t = 0; t < tsteps; ++t) {
        /* first update: B <- f(A) */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                B[i][j] = coef * (A[i][j] + A[i][j-1] + A[i][j+1] +
                                 A[i+1][j]  + A[i-1][j]);
            }
        }

        /* second update: A <- f(B) */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            for (int j = 1; j < n - 1; ++j) {
                A[i][j] = coef * (B[i][j] + B[i][j-1] + B[i][j+1] +
                                 B[i+1][j]  + B[i-1][j]);
            }
        }
    }
}
