```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    /* Basic cache‑blocking/kernels with OpenMP.  The algorithm
       is unchanged:  C := alpha*A*Aᵀ + beta*C.

       Matrix pointers are obtained once to avoid expensive
       std::vector indexing in the inner loops.
       The outer i‑loop is parallelised; each thread works on a
       distinct set of rows of C.  The inner loops are written
       in a highly efficient order to maximise reuse and minimise
       memory traffic.  A small tile size (64) is used for the
       j‑loop to keep working set small.  */
    const int tile = 64;       // tile size for the inner j‑loop

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci = C[i].data();   // pointer to row i of C
        const double* Ai = A[i].data();   // pointer to row i of A

        /* beta scaling of the lower triangular part of C */
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        /* compute alpha*A[i,*]*A[j,*] for all j <= i */
        for (int k = 0; k < m; ++k) {
            double aik = alpha * Ai[k];
            /* use a tile on the j‑dimension so that the
               working set fits into L1 / L2 cache */
            for (int jj = 0; jj <= i; jj += tile) {
                int jlim = (jj + tile <= i) ? jj + tile : i + 1;
                for (int j = jj; j < jlim; ++j) {
                    Ci[j] += aik * A[j][k];
                }
            }
        }
    }
}
