```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum) {

    // Work on raw pointers for maximal cache‑locality
    // `C4p[s][p]` accessed in the innermost loop
    const double* C4ptr = &C4[0][0];

    #pragma omp parallel for schedule(static)
    for (int r = 0; r < nr; ++r) {
        // `Apr[q][s]` accessed as A[r][q][s]
        const double* Apr = &A[r][0][0];  // Points to A[r][0][0]
        for (int q = 0; q < nq; ++q) {
            // Pointer to the start of the current row in A
            const double* Arow = Apr + q * np;
            // Reset sum for each p
            for (int p = 0; p < np; ++p) {
                sum[p] = 0.0;
            }
            // Accumulate products
            for (int s = 0; s < np; ++s) {
                const double val = Arow[s];
                const double* C4row = C4ptr + s * np;
                for (int p = 0; p < np; ++p) {
                    sum[p] += val * C4row[p];
                }
            }
            // Write back the result
            double* Astr = &A[r][q][0];
            for (int p = 0; p < np; ++p) {
                Astr[p] = sum[p];
            }
        }
    }
}
