/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_lu(int n, std::vector<std::vector<double>>& A)
{
    // Work with raw pointers for faster access
    double** rows = new double*[n];
    for (int i = 0; i < n; ++i) rows[i] = A[i].data();

    for (int i = 0; i < n; ++i)
    {
        // First part: fill column i (row > i)
        for (int j = 0; j < i; ++j)
        {
            double sum = 0.0;
            for (int k = 0; k < j; ++k)
                sum += rows[i][k] * rows[k][j];
            rows[i][j] -= sum;
            rows[i][j] /= rows[j][j];
        }

        // Second part: update remaining upper-triangular part
        for (int j = i; j < n; ++j)
        {
            double sum = 0.0;
            for (int k = 0; k < i; ++k)
                sum += rows[i][k] * rows[k][j];
            rows[i][j] -= sum;
        }
    }

    delete[] rows;
}
