#include <vector>
#include <omp.h>
#include <algorithm>
#include <numeric>

// Helper to get raw pointer to the innermost array of a row
inline double* row_ptr(std::vector<std::vector<double>>& v, size_t i)
{
    return v[i].data();
}

void kernel_covariance(int m, int n,
		       std::vector<std::vector<double>>& data,
		       std::vector<std::vector<double>>& cov,
		       std::vector<double>& mean)
{
    //--------------------
    // 1. Compute means
    //--------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s / n;
    }

    //--------------------
    // 2. Center data (subtract mean)
    //--------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = row_ptr(data, i);
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    //--------------------
    // 3. Compute covariance matrix
    //    We compute only the upper‑triangular part and mirror it.
    //--------------------
    const double inv = 1.0 / static_cast<double>(n - 1);
    #pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            cov[i][j] = s * inv;
            cov[j][i] = cov[i][j];
        }
    }
}
