/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Work on raw pointers to avoid bounds checks inside inner loops
    double* a = A.data();
    double* b = B.data();

    // Use one parallel region to keep the threads alive for all time steps
    #pragma omp parallel
    {
        for (int t = 0; t < tsteps; ++t) {
            // First sweep : A -> B
            #pragma omp for schedule(static)
            #pragma omp simd
            for (int i = 1; i < n - 1; ++i) {
                b[i] = 0.33333 * (a[i - 1] + a[i] + a[i + 1]);
            }

            // Second sweep : B -> A
            #pragma omp for schedule(static)
            #pragma omp simd
            for (int i = 1; i < n - 1; ++i) {
                a[i] = 0.33333 * (b[i - 1] + b[i] + b[i + 1]);
            }
        }
    }
