/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {

    // ------------------------------------------------------------------
    // 1st term :  x1 = x1 + A * y_1
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static) default(none) shared(n, x1, y_1, A)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double* prow = A[i].data();
        const double* yptr = y_1.data();
        // Vectorised accumulation (auto‑vectorised by the compiler)
        for (int j = 0; j < n; ++j) {
            sum += prow[j] * yptr[j];
        }
        x1[i] += sum;
    }

    // ------------------------------------------------------------------
    // 2nd term :  x2 = x2 + A^T * y_2   (column‑wise access)
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static) default(none) shared(n, x2, y_2, A)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double* yptr = y_2.data();
        // Accumulate over j: sum_j A[j][i] * y_2[j]
        for (int j = 0; j < n; ++j) {
            sum += A[j][i] * yptr[j];
        }
        x2[i] += sum;
    }
}
