syr2k:
```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    /* In order to keep the original API we do the work in terms of the
       2‑D std::vector interfaces, but we pull raw pointers out of the
       inner vectors once at the start.  This eliminates bounds checking
       and lets us use a tightly‑looped implementation with cache
       friendliness.  */
    std::vector<double*> Cptr(n);
    std::vector<double*> Apri(m);
    std::vector<double*> Bpri(m);
    for (int i = 0; i < n; ++i) Cptr[i] = C[i].data();
    for (int k = 0; k < m; ++k) Apri[k] = A[k].data();   // A is stored as N×M
    for (int k = 0; k < m; ++k) Bpri[k] = B[k].data();   // B is stored as N×M

    /* Parallelise over the outermost loop (the rows of C).  Each
       thread works on a distinct row i, so no parallelisation
       synchronization is required.  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* Ci = Cptr[i];

        /* C[i][j] = beta * C[i][j]  (lower triangle only) */
        for (int j = 0; j <= i; ++j)
            Ci[j] *= beta;

        /* Core syr2k accumulation.
           We pull the relevant columns of A and B into registers to
           reduce indirection.  */
        for (int k = 0; k < m; ++k) {
            const double* Ak = Apri[k];   // pointer to column k of A
            const double* Bk = Bpri[k];   // pointer to column k of B
            const double aik = Ak[i];
            const double bki = Bk[i];
            double* Bk_ptr = Bk;          // for B[j][k]
            double* Aj_ptr = Ak;          // for A[j][k]

            for (int j = 0; j <= i; ++j) {
                Ci[j] += alpha * (Aj_ptr[j] * bki + Bk_ptr[j] * aik);
            }
        }
    }
}
