```cpp
#include <vector>
#include <algorithm>
#include <cstring>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y)
{
    // Allocate work buffer once
    std::vector<double> z(n);

    // First step
    y[0] = -r[0];
    double beta   = 1.0;
    double alpha  = -r[0];

    // Main loop
    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        // Compute sum = Σ_{i=0}^{k-1} r[k-i-1] * y[i]
        double sum = 0.0;
        #pragma omp simd reduction(+:sum)
        for (int i = 0; i < k; ++i) {
            sum += r[k - i - 1] * y[i];
        }

        alpha = -(r[k] + sum) / beta;

        // Compute new y[0..k-1] into temporary z
        // Use symmetric update to avoid extra temporaries
        int hi = k - 1;
        for (int lo = 0; lo <= hi; ++lo) {
            z[lo] = y[lo] + alpha * y[hi - lo];
        }

        // Copy back to y[0..k-1]
        std::memcpy(&y[0], &z[0], k * sizeof(double));

        // Set new element
        y[k] = alpha;
    }
}
