/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* zero the output vectors */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        y[i] = 0.0;
    }
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        tmp[i] = 0.0;
    }

    /* GA+-style reduction on y array using GCC's array reduction extension */
    #pragma omp parallel for schedule(static) reduction(+: y[:n])
    for (int i = 0; i < m; ++i) {
        double sum = 0.0;
        const std::vector<double>& Arow = A[i];
        for (int j = 0; j < n; ++j) {
            sum += Arow[j] * x[j];
        }
        tmp[i] = sum;

        /* accumulate into y */
        for (int j = 0; j < n; ++j) {
            y[j] += Arow[j] * sum;
        }
    }
}
