#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* 1.  A[i][j] += u1[i]*v1[j] + u2[i]*v2[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ui1 = u1[i];
        double ui2 = u2[i];
        std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2.  x[i] += beta * sum_j A[j][i] * y[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp = 0.0;
        for (int j = 0; j < n; ++j) {
            tmp += A[j][i] * y[j];
        }
        x[i] += beta * tmp;
    }

    /* 3.  x[i] += z[i]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4.  w[i] += alpha * sum_j A[i][j] * x[j]  */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double tmp = 0.0;
        const std::vector<double>& Ai = A[i];
        for (int j = 0; j < n; ++j) {
            tmp += Ai[j] * x[j];
        }
        w[i] += alpha * tmp;
    }
}
