    const double inv_n = 1.0 / static_cast<double>(n);
    const double sqrt_n = std::sqrt(static_cast<double>(n));
    const double inv_sqrt_n = 1.0 / sqrt_n;

    // ---------- compute means ----------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) s += data[i][j];
        mean[j] = s * inv_n;
    }

    // ---------- compute stddev ----------
#pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sx = 0.0;
        double mu = mean[j];
        for (int i = 0; i < n; ++i) {
            double d = data[i][j] - mu;
            sx += d * d;
