        double var = sx * inv_n;
        double sdev = std::sqrt(var);
        stddev[j] = (sdev <= eps) ? 1.0 : sdev;
    }

    // ---------- normalize data ----------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            double val = data[i][j] - mean[j];
            val /= inv_sqrt_n * stddev[j]; // multiplying by inv_sqrt_n below
            data[i][j] = val;
        }
    }

    // ---------- compute correlation matrix ----------
    // initialize diagonal
    corr[m-1][m-1] = 1.0;
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {
                s += data[k][i] * data[k][j];
            }
            corr[i][j] = s;
            corr[j][i] = s;
        }
    }
}
