/* QR Decomposition with Modified Gram Schmidt.
 * Maintains exact numeric behaviour of the reference kernel
 * while exploiting data‑parallelism on modern x86‑64 CPUs.
 */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {

    /* Outer loop over columns must remain sequential */
    for (int k = 0; k < n; ++k) {
        /* Compute norm of the k‑th column of A  (∑ A[i][k]^2)   */
        double norm2 = 0.0;
        #pragma omp parallel for reduction(+:norm2) schedule(static)
        for (int i = 0; i < m; ++i)
            norm2 += A[i][k] * A[i][k];

        double rkk = std::sqrt(norm2);
        R[k][k] = rkk;

        /* Q[:,k] = A[:,k] / rkk  */
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i)
            Q[i][k] = A[i][k] / rkk;

        /* Process remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            /* R[k][j] = Q[:,k]^T * A[:,j] */
            #pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i)
                rkj += Q[i][k] * A[i][j];
            R[k][j] = rkj;

            /* A[:,j] -= Q[:,k] * R[k][j] */
            #pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i)
                A[i][j] -= Q[i][k] * rkj;
        }
    }
}
