#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    /* Parallelize the outer loop. Each iteration works on independent rows. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        const double* Ai = A[i].data();      // row of A
        const double* Bi = B[i].data();      // row of B
        const double* px = x.data();         // vector x

        double tmpi = 0.0;
        double yi   = 0.0;

        /* Use a vectorised unroll of 4 elements. */
        int j = 0;
        int unroll = 4;
        int limit = n - (n % unroll);
        for (; j < limit; j += unroll) {
            tmpi += Ai[j]   * px[j];
            yi   += Bi[j]   * px[j];

            tmpi += Ai[j+1] * px[j+1];
            yi   += Bi[j+1] * px[j+1];

            tmpi += Ai[j+2] * px[j+2];
            yi   += Bi[j+2] * px[j+2];

            tmpi += Ai[j+3] * px[j+3];
            yi   += Bi[j+3] * px[j+3];
        }
        /* Handle any remaining elements that don't fit the unroll. */
        for (; j < n; ++j) {
            tmpi += Ai[j] * px[j];
            yi   += Bi[j] * px[j];
        }

        /* Final scaling step as in the original kernel. */
        y[i]   = alpha * tmpi + beta * yi;
        tmp[i] = tmpi;   // preserve the state of `tmp` as expected
    }
}
