/* 
 * Optimised 2‑D FDTD kernel.
 * All arrays are kept as std::vector<std::vector<double>> to preserve the
 * interface, but during the loop we obtain raw pointers to the underlying
 * contiguous storage for maximum bandwidth utilisation.
 */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {

    /* pre‑fetch raw pointers for all rows – the outer vector is guaranteed
     * to be contiguous in C++11/14/17 onwards.
     */
    std::vector<double*> ex_ptrs(nx), ey_ptrs(nx), hz_ptrs(nx);
    for (int i = 0; i < nx; ++i) {
        ex_ptrs[i]  = ex[i].data();
        ey_ptrs[i]  = ey[i].data();
        hz_ptrs[i]  = hz[i].data();
    }

    const double c1 = 0.5;
    const double c2 = 0.7;

    /* The outermost time loop is intentionally left sequential – data
     * dependencies between time steps prevent parallelism here, but the
     * inner spatial loops are well suited to OpenMP.
     */
    for (int t = 0; t < tmax; ++t) {
        /* Boundary update – vectorised by compiler */
        double f = _fict_[t];
        #pragma omp parallel for
        for (int j = 0; j < ny; ++j) {
            ey_ptrs[0][j] = f;
        }

        /* Update Ey component */
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < nx; ++i) {
            double* ey_cur = ey_ptrs[i];
            double* ey_prev = ey_ptrs[i-1];
            double* hz_cur = hz_ptrs[i];
            double* hz_prev = hz_ptrs[i-1];
            for (int j = 0; j < ny; ++j) {
                ey_cur[j] -= c1 * (hz_cur[j] - hz_prev[j]);
            }
        }

        /* Update Ex component */
        #pragma omp parallel for collapse(2)
        for (int i = 0; i < nx; ++i) {
            double* ex_cur = ex_ptrs[i];
            double* hz_cur = hz_ptrs[i];
            double* hz_prev = (j>0) ? hz_ptrs[i] : hz_ptrs[i];
            for (int j = 1; j < ny; ++j) {
                ex_cur[j] -= c1 * (hz_cur[j] - hz_cur[j-1]);
            }
        }

        /* Update Hz component – one iteration less in both dimensions */
        #pragma omp parallel for collapse(2)
        for (int i = 0; i < nx-1; ++i) {
            double* hz_cur = hz_ptrs[i];
            double* hz_next = hz_ptrs[i+1];
            double* ex_cur = ex_ptrs[i];
            double* ex_next = ex_ptrs[i];
            double* ey_cur = ey_ptrs[i];
            double* ey_next = ey_ptrs[i+1];
            for (int j = 0; j < ny-1; ++j) {
                hz_cur[j] -= c2 * (ex_cur[j+1] - ex_cur[j]
                                  + ey_next[j]   - ey_cur[j]);
            }
        }
    }
}
