/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    /* obtain raw pointers to rows for fast access */
    std::vector<double*> prow(n);
    for (int i = 0; i < n; ++i) prow[i] = A[i].data();

    /* LU decomposition – forward sweep */
    for (int i = 0; i < n; ++i)
    {
        double* Ai   = prow[i];
        double* Aii  = prop(i,i) ? &Ai[i] : nullptr; /* alias for Ai[i] */

        /* first part: L part with division by pivot */
        for (int j = 0; j < i; ++j)
        {
            double w = Ai[j];
            double* Aj = prow[j];
            /* inner dot product (k < j) */
            for (int k = 0; k < j; ++k)
                w -= Ai[k] * Aj[k];
            Ai[j] = w / Aj[j];
        }

        /* second part: U part */
        for (int j = i; j < n; ++j)
        {
            double w = Ai[j];
            /* inner dot product (k < i) */
            for (int k = 0; k < i; ++k)
                w -= Ai[k] * prow[k][j];
            Ai[j] = w;
        }
    }

    /* forward substitution: y = L⁻¹ * b */
    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        double* Ai = prow[i];
        for (int j = 0; j < i; ++j)
            w -= Ai[j] * y[j];
        y[i] = w;
    }

    /* backward substitution: x = U⁻¹ * y */
    for (int i = n - 1; i >= 0; --i)
    {
        double w = y[i];
        double* Ai = prow[i];
        for (int j = i + 1; j < n; ++j)
            w -= Ai[j] * x[j];
        x[i] = w / Ai[i];
    }
}
