#include <omp.h>

/* main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_bicg(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& s,
                 std::vector<double>& q,
                 std::vector<double>& p,
                 std::vector<double>& r)
{
    /* flatten the 2‑D matrix to a 1‑D contiguously stored array
       so the compiler can generate cache‑friendly code.  The
       layout is row‑major: A[i][j] -> flat[i*m + j] */
    std::vector<double> flatA(static_cast<std::size_t>(m) * n);
    for (int i = 0; i < m; ++i)
        for (int j = 0; j < n; ++j)
            flatA[static_cast<std::size_t>(i) * n + j] = A[i][j];

    /* 1) compute sum of p once (independent of i) */
    double sumP = 0.0;
    #pragma omp parallel for reduction(+:sumP)
    for (int j = 0; j < n; ++j)
        sumP += p[j];

    /* 2) compute s[j] = Σ_i r[i] * A[i][j]   (parallel over j) */
    #pragma omp parallel for
    for (int j = 0; j < n; ++j) {
        double tmp = 0.0;
        for (int i = 0; i < m; ++i) {
            double a_ij = flatA[static_cast<std::size_t>(i) * n + j];
            tmp += r[i] * a_ij;
        }
        s[j] = tmp;
    }

    /* 3) compute q[i] = Σ_j A[i][j] + sumP   (parallel over i) */
    #pragma omp parallel for
    for (int i = 0; i < m; ++i) {
        double rowSum = 0.0;
        for (int j = 0; j < n; ++j)
            rowSum += flatA[static_cast<std::size_t>(i) * n + j];
        q[i] = rowSum + sumP;
    }
}
