#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* ----------------------------------------------------------------------
   Optimised 2‑matrix multiply kernel.
   ---------------------------------------------------------------------- */

constexpr std::size_t BLOCK_SIZE = 64;   // Tune for cache / vector width

void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha,
                double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* --------------------------------------------------------------
       Flatten the 2‑D std::vector containers for better data locality.
       -------------------------------------------------------------- */
    double *tmp_ptr = new double[ni * nj];
    double *A_ptr   = &A[0][0];
    double *B_ptr   = &B[0][0];
    double *C_ptr   = &C[0][0];
    double *D_ptr   = &D[0][0];

    /* 1st phase: compute tmp = alpha * A * B                       */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int ii = 0; ii < ni; ii += BLOCK_SIZE) {
        for (int jj = 0; jj < nj; jj += BLOCK_SIZE) {
            const int i_max = std::min(ii + BLOCK_SIZE, ni);
            const int j_max = std::min(jj + BLOCK_SIZE, nj);
            for (int i = ii; i < i_max; ++i) {
                double *tmp_row = tmp_ptr + i * nj;
                const double *Ai = A_ptr + i * nk;
                for (int j = jj; j < j_max; ++j) {
                    double sum = 0.0;
                    const double *Bcol = B_ptr + j;
                    for (int k = 0; k < nk; ++k) {
                        sum += alpha * Ai[k] * Bcol[k * nj];
                    }
                    tmp_row[j] = sum;
                }
            }
        }
    }

    /* 2nd phase: D = beta * D + tmp * C                            */
    #pragma omp parallel for schedule(static) collapse(2)
    for (int ii = 0; ii < ni; ii += BLOCK_SIZE) {
        for (int jj = 0; jj < nl; jj += BLOCK_SIZE) {
            const int i_max = std::min(ii + BLOCK_SIZE, ni);
            const int j_max = std::min(jj + BLOCK_SIZE, nl);
            for (int i = ii; i < i_max; ++i) {
                double *Drow = D_ptr + i * nl;
                const double *tmp_row = tmp_ptr + i * nj;
                for (int j = jj; j < j_max; ++j) {
                    double acc = beta * Drow[j];
                    const double *Ccol = C_ptr + j;
                    for (int k = 0; k < nj; ++k) {
                        acc += tmp_row[k] * Ccol[k * nl];
                    }
                    Drow[j] = acc;
                }
            }
        }
    }

    /* Copy back the result from the linear buffer to the std::vector. */
    for (int i = 0; i < ni; ++i)
        for (int j = 0; j < nl; ++j)
            D[i][j] = D_ptr[i * nl + j];

    delete[] tmp_ptr;
}
