#include <vector>
#include <omp.h>

constexpr double coeff = 0.125;

// helper to linearize 3‑D index
inline std::size_t id(int i, int j, int k, int nx, int ny)
{
    return static_cast<std::size_t>(i) * ny * nx + static_cast<std::size_t>(j) * nx + static_cast<std::size_t>(k);
}

// main kernel
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    const int nx = n, ny = n, nz = n;
    const std::size_t size = static_cast<std::size_t>(n) * n * n;

    // convert 3‑D containers to flattened 1‑D arrays
    std::vector<double> a_flat(size), b_flat(size);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                a_flat[id(i, j, k, nx, ny)] = A[i][j][k];

    for (int t = 1; t <= tsteps; ++t)
    {
        // compute B from A
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n-1; ++i)
            for (int j = 1; j < n-1; ++j)
                for (int k = 1; k < n-1; ++k)
                {
                    std::size_t p = id(i, j, k, nx, ny);
                    double v = a_flat[p];
                    double nf = a_flat[id(i+1, j, k, nx, ny)];
                    double bp = a_flat[id(i-1, j, k, nx, ny)];
                    double nf2 = a_flat[id(i, j+1, k, nx, ny)];
                    double bp2 = a_flat[id(i, j-1, k, nx, ny)];
                    double nf3 = a_flat[id(i, j, k+1, nx, ny)];
                    double bp3 = a_flat[id(i, j, k-1, nx, ny)];
                    b_flat[p] = coeff * (nf - 2.0*v + bp)
                              + coeff * (nf2 - 2.0*v + bp2)
                              + coeff * (nf3 - 2.0*v + bp3)
                              + v;
                }

        // swap buffers: reuse a_flat for next step
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n-1; ++i)
            for (int j = 1; j < n-1; ++j)
                for (int k = 1; k < n-1; ++k)
                {
                    std::size_t p = id(i, j, k, nx, ny);
                    double v = b_flat[p];
                    double nf = b_flat[id(i+1, j, k, nx, ny)];
                    double bp = b_flat[id(i-1, j, k, nx, ny)];
                    double nf2 = b_flat[id(i, j+1, k, nx, ny)];
                    double bp2 = b_flat[id(i, j-1, k, nx, ny)];
                    double nf3 = b_flat[id(i, j, k+1, nx, ny)];
                    double bp3 = b_flat[id(i, j, k-1, nx, ny)];
                    a_flat[p] = coeff * (nf - 2.0*v + bp)
                              + coeff * (nf2 - 2.0*v + bp2)
                              + coeff * (nf3 - 2.0*v + bp3)
                              + v;
                }
    }

    // copy back to original containers
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                A[i][j][k] = a_flat[id(i, j, k, nx, ny)];
}
