```cpp
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    // Reorder the loops so that each column j is independent.
    // We can safely parallelise over the outermost dimension.
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < n; ++j) {
        for (int i = 0; i < m; ++i) {
            double temp2 = 0.0;
            double B_ij = B[i][j];
            double A_ii = A[i][i];
            double alpha_B_ij = alpha * B_ij;

            // Unroll the inner k‑loop a bit for better pipeline utilisation.
            int k = 0;
            // Handle k in blocks of 4
            for (; k <= i - 4; k += 4) {
                double a0 = A[i][k];
                double a1 = A[i][k + 1];
                double a2 = A[i][k + 2];
                double a3 = A[i][k + 3];

                double b0 = B[k][j];
                double b1 = B[k + 1][j];
                double b2 = B[k + 2][j];
                double b3 = B[k + 3][j];

                C[k][j] += alpha_B_ij * a0;
                C[k + 1][j] += alpha_B_ij * a1;
                C[k + 2][j] += alpha_B_ij * a2;
                C[k + 3][j] += alpha_B_ij * a3;

                temp2 += b0 * a0 + b1 * a1 + b2 * a2 + b3 * a3;
            }
            // Tail handling
            for (; k < i; ++k) {
                double a = A[i][k];
                C[k][j] += alpha_B_ij * a;
                temp2 += B[k][j] * a;
            }

            C[i][j] = beta * C[i][j] + alpha_B_ij * A_ii + alpha * temp2;
        }
    }
}
