nussinov:
```cpp
#include <vector>
#include <algorithm>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table) {

    // Work by strand length (j-i).  Each length can be processed in parallel
    for (int len = 1; len < n; ++len) {
        // i ranges from 0 to n-len-1
        #pragma omp parallel for schedule(static)
        for (int i = 0; i + len < n; ++i) {
            int j = i + len;
            int best = 0;

            // References to rows to avoid repeated vector indexing
            const std::vector<int>& row_i   = table[i];
            const std::vector<int>& row_ip1 = table[i+1];

            // Indirect matches (if any)
            int match = (seq[i] + seq[j] == 3) ? 1 : 0;

            // Table[i][j-1]
            best = std::max(best, row_i[j-1]);

            // Table[i+1][j]
            best = std::max(best, row_ip1[j]);

            // Table[i+1][j-1] + match
            if (i < j-1)
                best = std::max(best, row_ip1[j-1] + match);
            else
                best = std::max(best, row_ip1[j-1]);

            // Split over k
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, row_i[k] + row_ip1[k+1]);
            }

            table[i][j] = best;
        }
    }
}
