    double *b = const_cast<double*>(B[0].data());
    double *c = const_cast<double*>(C[0].data());
    double *d = const_cast<double*>(D[0].data());
    double *e = const_cast<double*>(E[0].data());
    double *f = const_cast<double*>(F[0].data());
    double *g = const_cast<double*>(G[0].data());

