    const std::size_t strideB = colsB;
    const std::size_t strideC = colsC;
    const std::size_t strideD = colsD;
    const std::size_t strideE = colsE;
    const std::size_t strideF = colsF;
    const std::size_t strideG = colsG;

    /* 1) E = A * B   (ni x nj) */
    #pragma omp parallel for schedule(static, 8) collapse(1)
    for (int i = 0; i < ni; ++i) {
        double *e_row = e + i * strideE;
        const double *a_row = a + i * strideA;
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double *b_col = b + j;
            for (int k = 0; k < nk; ++k) {
                sum += a_row[k] * b_col[k * strideB];
            }
            e_row[j] = sum;
        }
    }

    /* 2) F = C * D   (nj x nl) */
    #pragma omp parallel for schedule(static, 8) collapse(1)
    for (int i = 0; i < nj; ++i) {
        double *f_row = f + i * strideF;
        const double *c_row = c + i * strideC;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double *d_col = d + j;
            for (int k = 0; k < nm; ++k) {
                sum += c_row[k] * d_col[k * strideD];
            }
            f_row[j] = sum;
        }
    }

    /* 3) G = E * F   (ni x nl) */
    #pragma omp parallel for schedule(static, 8) collapse(1)
    for (int i = 0; i < ni; ++i) {
        double *g_row = g + i * strideG;
        const double *e_row = e + i * strideE;
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double *f_col = f + j;
            for (int k = 0; k < nj; ++k) {
                sum += e_row[k] * f_col[k * strideF];
            }
            g_row[j] = sum;
        }
    }
