#include <vector>
#include <omp.h>

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A)
{
    /*  Assume that A is contiguous in memory (row major).
        Create a second temporary array of the same size */
    std::vector<std::vector<double>> B(n, std::vector<double>(n));

    /* Pointer arithmetic helpers for the two buffers */
    const int stride = n;
    const double inv9 = 1.0 / 9.0;

    /* Initial copy of A into B (so that B holds the current state) */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            B[i][j] = A[i][j];

    /* Main time‐stepping loop.
       We alternate between B -> A and A -> B, so that the data
       needed for the next step is still intact. */
    for (int t = 0; t < tsteps; ++t)
    {
        /* Alias for faster access */
        std::vector<std::vector<double>>& src = (t & 1) ? B : A;
        std::vector<std::vector<double>>& dst = (t & 1) ? A : B;

        /* Update interior points.  The outer loop is serial because
           each row depends on the previous row from the same time
           step.  The inner loop is embarrassingly parallel. */
        for (int i = 1; i <= n - 2; ++i)
        {
#pragma omp parallel for schedule(static)
            for (int j = 1; j <= n - 2; ++j)
            {
                dst[i][j] =
                    ( src[i-1][j-1] + src[i-1][j] + src[i-1][j+1]
                    + src[i  ][j-1] + src[i  ][j] + src[i  ][j+1]
                    + src[i+1][j-1] + src[i+1][j] + src[i+1][j+1] ) * inv9;
            }
        }

        /* Boundary values are unchanged */
        for (int i = 0; i < n; ++i) {
            dst[i][0]     = src[i][0];
            dst[i][n-1]   = src[i][n-1];
        }
        for (int j = 0; j < n; ++j) {
            dst[0][j]     = src[0][j];
            dst[n-1][j]   = src[n-1][j];
        }
    }

    /* If the number of steps is odd, the results are in B.  We
       copy them back into A so that the function signature
       remains unchanged. */
    if (tsteps & 1) {
        for (int i = 0; i < n; ++i)
            for (int j = 0; j < n; ++j)
                A[i][j] = B[i][j];
    }
}
