#include <vector>
#include <omp.h>

/*
 * Optimised version of kernel_adi.
 * See the original comments for a description of the algorithm.
 */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    // Pre‑compute constants that do not change per time step
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a  = -mul1 / 2.0;
    const double b  = 1.0 + mul1;
    const double c  = a;
    const double d  = -mul2 / 2.0;
    const double e  = 1.0 + mul2;
    const double f  = d;

    // Main time‑stepping loop
    for (int t = 1; t <= tsteps; ++t)
    {
        /* ----------------------------------------------------------
         * First sweep (build v from u)
         * ---------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* vrow      = &v[0][i];
            double* urow_i_1  = &u[0][i - 1];
            double* urow_i    = &u[0][i];
            double* urow_ip1  = &u[0][i + 1];
            double* prow      = &p[0][i];
            double* qrow      = &q[0][i];

            /* initialise first column */
            v[0][i] = 1.0;
            p[i][0] = 0.0;          // reused later
            q[i][0] = v[0][i];

            /* forward sweep (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j)
            {
                const double denom = a * p[j - 1] + b;   // a*p[j-1] + b
                p[j] = -c / denom;
                q[j] = (-d * urow_i_1[j] + (1.0 + 2.0 * d) * urow_i[j]
                        - f * urow_ip1[j] - a * q[j - 1]) / denom;
            }

            v[n - 1][i] = 1.0;

            /* backward sweep (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j)
            {
                v[j][i] = p[j] * v[j + 1][i] + q[j];
            }
        }

        /* ----------------------------------------------------------
         * Second sweep (build u from v)
         * ---------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
        {
            double* urow      = &u[0][i];
            double* vrow_i_1  = &v[0][i - 1];
            double* vrow_i    = &v[0][i];
            double* vrow_ip1  = &v[0][i + 1];
            double* prow      = &p[0][i];
            double* qrow      = &q[0][i];

            /* initialise first column */
            u[i][0] = 1.0;
            p[i][0] = 0.0;          // reused later
            q[i][0] = u[i][0];

            /* forward sweep (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j)
            {
                const double denom = d * p[j - 1] + e;   // d*p[j-1] + e
                p[j] = -f / denom;
                q[j] = (-a * vrow_i_1[j] + (1.0 + 2.0 * a) * vrow_i[j]
                        - c * vrow_ip1[j] - d * q[j - 1]) / denom;
            }

            u[i][n - 1] = 1.0;

            /* backward sweep (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j)
            {
                u[i][j] = p[j] * u[i][j + 1] + q[j];
            }
        }
    }
}
