```cpp
// Optimised version – no change to the original function signature.
// The kernel is re‑implemented with contiguous 1‑D storage,
// all expensive mathematical operations are pre‑computed,
// and OpenMP is used to parallelise independent row/column passes.

#include <cmath>
#include <vector>
#include <omp.h>

static inline float idx(int i, int j, int h) { return i * h + j; }

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* --------------------------------------------------------------- */
    /* 1.  Convert all 2‑D references into 1‑D contiguous vectors      */
    /* --------------------------------------------------------------- */
    const size_t N = static_cast<size_t>(w) * h;

    std::vector<float> in(N), out(N), y1_1d(N), y2_1d(N);

    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            in[idx(i,j,h)]   = imgIn[i][j];
            out[idx(i,j,h)]  = imgOut[i][j];
            y1_1d[idx(i,j,h)] = 0.0f;
            y2_1d[idx(i,j,h)] = 0.0f;
        }
    }

    /* --------------------------------------------------------------- */
    /* 2.  Pre‑compute constants                                         */
    /* --------------------------------------------------------------- */
    const float expa      = std::exp(-alpha);
    const float exp2a     = std::exp(-2.0 * alpha);
    const float den        = 1.0f + 2.0f * static_cast<float>(alpha) * expa - exp2a;
    const float k          = 1.0f - expa * (1.0f - expa) / den;

    const float a1 = k,                     a5 = k;
    const float a2 = k * expa * (static_cast<float>(alpha) - 1.0f),  a6 = a2;
    const float a3 = k * expa * (static_cast<float>(alpha) + 1.0f),  a7 = a3;
    const float a4 = -k * exp2a,           a8 = a4;

    const float b1 = std::pow(2.0f, -static_cast<float>(alpha));
    const float b2 = -exp2a;
    const float c1 = 1.0f, c2 = 1.0f;   // identical in the original code

    /* --------------------------------------------------------------- */
    /* 3.  Forward pass – rows                                         */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float val = in[idx(i,j,h)];
            const float y   = a1 * val + a2 * xm1 + b1 * ym1 + b2 * ym2;
            y1_1d[idx(i,j,h)] = y;
            xm1 = val;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* --------------------------------------------------------------- */
    /* 4.  Backward pass – rows                                         */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h - 1; j >= 0; --j) {
            const float val = in[idx(i,j,h)];
            const float y   = a3 * xp1 + a4 * xp2 + b1 * yp1 + b2 * yp2;
            y2_1d[idx(i,j,h)] = y;
            xp2 = xp1;
            xp1 = val;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* --------------------------------------------------------------- */
    /* 5.  Merge (horizontal)                                           */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i,j,h)] = c1 * (y1_1d[idx(i,j,h)] + y2_1d[idx(i,j,h)]);

    /* --------------------------------------------------------------- */
    /* 6.  Forward pass – columns                                      */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float val = out[idx(i,j,h)];
            const float y   = a5 * val + a6 * tm1 + b1 * ym1 + b2 * ym2;
            y1_1d[idx(i,j,h)] = y;
            tm1 = val;
            ym2 = ym1;
            ym1 = y;
        }
    }

    /* --------------------------------------------------------------- */
    /* 7.  Backward pass – columns                                     */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w - 1; i >= 0; --i) {
            const float val = out[idx(i,j,h)];
            const float y   = a7 * tp1 + a8 * tp2 + b1 * yp1 + b2 * yp2;
            y2_1d[idx(i,j,h)] = y;
            tp2 = tp1;
            tp1 = val;
            yp2 = yp1;
            yp1 = y;
        }
    }

    /* --------------------------------------------------------------- */
    /* 8.  Final merge (vertical)                                      */
    /* --------------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[idx(i,j,h)] = c2 * (y1_1d[idx(i,j,h)] + y2_1d[idx(i,j,h)]);

    /* --------------------------------------------------------------- */
    /* 9.  Copy results back to the original 2‑D containers           */
    /* --------------------------------------------------------------- */
    for (int i = 0; i < w; ++i) {
        for (int j = 0; j < h; ++j) {
            imgOut[i][j] = out[idx(i,j,h)];
            y1[i][j]     = y1_1d[idx(i,j,h)];
            y2[i][j]     = y2_1d[idx(i,j,h)];
        }
    }
}
